package com.oneil.wellness.walkplanner.activity;import com.oneil.wellness.walkplanner.history.*;import java.time.*;import java.util.Set;import org.slf4j.*;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;@Service public class OpportunityExpiryService{private static final Logger log=LoggerFactory.getLogger(OpportunityExpiryService.class);private static final Set<ActivityStatus> ACTIONED=Set.of(ActivityStatus.ACTIVE,ActivityStatus.COMPLETED,ActivityStatus.PARTIALLY_COMPLETED);private final HistoryRepository history;private final OpportunityOutcomeRepository outcomes;private final WalkActivityRepository activities;public OpportunityExpiryService(HistoryRepository h,OpportunityOutcomeRepository o,WalkActivityRepository a){history=h;outcomes=o;activities=a;}@Scheduled(cron="${opportunity.expiry.cron:0 */15 * * * *}")@Transactional public int classify(){int count=0;OffsetDateTime now=OffsetDateTime.now(ZoneOffset.UTC);for(RecommendationHistory recommendation:history.findTop100ByRecommendedEndBeforeAndCalendarAvailableTrueAndScoreGreaterThanEqualOrderByRecommendedEndAsc(now,60)){if(outcomes.findByRecommendationHistoryId(recommendation.getId()).isPresent())continue;boolean acted=activities.findByOpportunityStartAndOpportunityEnd(recommendation.getRecommendedStart(),recommendation.getRecommendedEnd()).stream().anyMatch(v->ACTIONED.contains(v.getActivityStatus()));if(acted)continue;outcomes.save(new OpportunityOutcome(recommendation.getId(),ActivityStatus.EXPIRED,ActivitySource.HISTORY));count++;}log.info("Opportunity expiry classified={} batchLimit=100",count);return count;}}
